import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjProgress } from "./OjProgress";
export { OjProgress };

/**
 * Create an instance of [[OjProgress]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojProgress(driver, By.id('my-oj-progress'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojProgress(driver: DriverLike, by: By): Promise<OjProgress> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjProgress
  if (!(webEl instanceof OjProgress)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-progress>`);
  }
  return webEl;
}

register("oj-progress", OjProgress);
